templates.api_dev:
{api_service}:
  image: {api_image}
  container_name: {api_service}
  build:
    context: {api_context}
    dockerfile: {api_dockerfile_dev}
  ports:
    - "${{API_PORT:-8090}}:${{API_PORT:-8090}}"
  env_file:
    - {secrets_backend}/.env.dev
  environment:
    SPRING_PROFILES_ACTIVE: dev
  networks:
    - {network_key}
  restart: unless-stopped
  healthcheck:
    test: ["CMD-SHELL", "wget -qO- http://localhost:${{API_PORT:-8090}}/health | grep -q UP || exit 1"]
    interval: {health_interval}
    timeout: 5s
    retries: {health_retries}
    start_period: {health_start}

templates.worker_dev:
{worker_service}:
  image: {worker_image}
  container_name: {worker_service}
  build:
    context: {worker_context}
    dockerfile: {worker_dockerfile_dev}
  ports:
    - "${{WORKER_PORT:-8091}}:${{WORKER_PORT:-8091}}"
  env_file:
    - {secrets_backend}/.env.dev
  environment:
    SPRING_PROFILES_ACTIVE: dev
    API_INTERNAL_URL: ${{API_INTERNAL_URL:-http://{api_service}:${{API_PORT:-8090}}}}
  depends_on:
    {api_service}:
      condition: service_healthy
  networks:
    - {network_key}
  restart: unless-stopped
  healthcheck:
    test: ["CMD-SHELL", "wget -qO- http://localhost:${{WORKER_PORT:-8091}}/actuator/health | grep -q UP || exit 1"]
    interval: {health_interval}
    timeout: 5s
    retries: {health_retries}
    start_period: {health_start}

templates.app_base:
{app_service}:
  image: {app_image}
  container_name: {app_service}
  build:
    context: {app_context}
    dockerfile: src/Dockerfile
